import android.util.Base64
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.fragment.app.FragmentActivity
import javax.crypto.Cipher
import javax.crypto.spec.GCMParameterSpec

class BiometricAuthManager(
    private val activity: FragmentActivity,
    private val tokenStore: TokenStore            // see below
) {

    sealed interface AuthResult {
        data class Success(val sessionToken: String) : AuthResult
        data class Error(val message: String)        : AuthResult
        object Canceled                              : AuthResult
        object KeyInvalidated                        : AuthResult
    }

    fun retrieveSessionToken(onResult: (AuthResult) -> Unit) {
        val stored = tokenStore.loadEncryptedToken()
        if (stored == null) {
            onResult(AuthResult.Error("No session token stored — please log in."))
            return
        }

        val key = try {
            KeystoreHelper.getOrCreateKey()
        } catch (e: android.security.keystore.KeyPermanentlyInvalidatedException) {
            tokenStore.clear()
            onResult(AuthResult.KeyInvalidated)
            return
        }

        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(
            Cipher.DECRYPT_MODE,
            key,
            GCMParameterSpec(128, Base64.decode(stored.iv, Base64.NO_WRAP))
        )

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Confirm your identity")
            .setSubtitle("Required to start a Claude conversation")
            .setAllowedAuthenticators(
                androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG or
                androidx.biometric.BiometricManager.Authenticators.DEVICE_CREDENTIAL
            )
            .build()

        val prompt = BiometricPrompt(
            activity,
            ContextCompat.getMainExecutor(activity),
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationSucceeded(
                    result: BiometricPrompt.AuthenticationResult
                ) {
                    val authenticatedCipher = result.cryptoObject!!.cipher!!
                    val plaintext = String(
                        authenticatedCipher.doFinal(
                            Base64.decode(stored.ciphertext, Base64.NO_WRAP)
                        ),
                        Charsets.UTF_8
                    )
                    onResult(AuthResult.Success(plaintext))
                }

                override fun onAuthenticationError(
                    errorCode: Int,
                    errString: CharSequence
                ) {
                    if (errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                        errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                        onResult(AuthResult.Canceled)
                    } else {
                        onResult(AuthResult.Error(errString.toString()))
                    }
                }

                override fun onAuthenticationFailed() {
                    // Single failed attempt; the prompt continues — do nothing
                }
            }
        )

        prompt.authenticate(promptInfo, BiometricPrompt.CryptoObject(cipher))
    }
}

// Minimal companion data holder
data class EncryptedToken(val iv: String, val ciphertext: String)

interface TokenStore {
    fun loadEncryptedToken(): EncryptedToken?
    fun clear()
}

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

sealed interface ChatUiState {
    object Idle                                   : ChatUiState
    object AwaitingBiometric                      : ChatUiState
    data class Streaming(val partial: String)     : ChatUiState
    data class Error(val message: String)         : ChatUiState
    object ReauthRequired                         : ChatUiState  // key invalidated
}

class ChatViewModel(
    private val authManager: BiometricAuthManager,
    private val repository: ClaudeRepository
) : ViewModel() {

    private val _state = MutableStateFlow<ChatUiState>(ChatUiState.Idle)
    val state: StateFlow<ChatUiState> = _state.asStateFlow()

    fun sendMessage(userText: String) {
        _state.update { ChatUiState.AwaitingBiometric }

        authManager.retrieveSessionToken { result ->
            when (result) {
                is BiometricAuthManager.AuthResult.Success -> {
                    // Biometric passed — proceed with Claude API call via proxy
                    viewModelScope.launch {
                        streamWithToken(result.sessionToken, userText)
                    }
                }
                is BiometricAuthManager.AuthResult.Error -> {
                    _state.update { ChatUiState.Error(result.message) }
                }
                BiometricAuthManager.AuthResult.Canceled -> {
                    _state.update { ChatUiState.Idle }   // user dismissed; restore input
                }
                BiometricAuthManager.AuthResult.KeyInvalidated -> {
                    _state.update { ChatUiState.ReauthRequired }
                }
            }
        }
    }

    private suspend fun streamWithToken(token: String, text: String) {
        try {
            _state.update { ChatUiState.Streaming("") }
            repository.stream(token, text).collect { delta ->
                _state.update { current ->
                    val existing = (current as? ChatUiState.Streaming)?.partial ?: ""
                    ChatUiState.Streaming(existing + delta)
                }
            }
            _state.update { ChatUiState.Idle }
        } catch (e: Exception) {
            _state.update { ChatUiState.Error(e.message ?: "Unknown error") }
        }
    }
}

import android.content.SharedPreferences
import android.util.Base64
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class SharedPrefsTokenStore(private val prefs: SharedPreferences) : TokenStore {

    // Called after a successful backend login — run on Dispatchers.IO
    suspend fun storeSessionToken(plainToken: String) = withContext(Dispatchers.IO) {
        val key = KeystoreHelper.getOrCreateKey()
        val (iv, ciphertext) = KeystoreHelper.encrypt(plainToken, key)
        prefs.edit()
            .putString("token_iv",         Base64.encodeToString(iv, Base64.NO_WRAP))
            .putString("token_ciphertext",  Base64.encodeToString(ciphertext, Base64.NO_WRAP))
            .apply()
    }

    override fun loadEncryptedToken(): EncryptedToken? {
        val iv         = prefs.getString("token_iv", null) ?: return null
        val ciphertext = prefs.getString("token_ciphertext", null) ?: return null
        return EncryptedToken(iv = iv, ciphertext = ciphertext)
    }

    override fun clear() {
        prefs.edit().remove("token_iv").remove("token_ciphertext").apply()
        // Also remove the Keystore key so it regenerates cleanly on next login
        val ks = java.security.KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
        ks.deleteEntry(KeystoreHelper.KEY_ALIAS)
    }
}
